# IVMS101.2023 Cheat Sheet (structures, multiplicities, datatypes, key constraints)
# Source: IVMS101.2023 interVASP data model standard (Issue 1, FINAL)

payloadMetadata:
  description: Metadata describing the payload.
  fields:
    payloadVersion:
      type: Text
      example: "IVMS101.2023"

Address:
  structure:
    addressType: { multiplicity: "[1..1]", type: "AddressTypeCode" }
    department: { multiplicity: "[0..1]", type: "Max50Text" }
    subDepartment: { multiplicity: "[0..1]", type: "Max70Text" }
    streetName: { multiplicity: "[0..1]", type: "Max70Text", constraints: ["C8"] }
    buildingNumber: { multiplicity: "[0..1]", type: "Max16Text", constraints: ["C8"] }
    buildingName: { multiplicity: "[0..1]", type: "Max35Text", constraints: ["C8"] }
    floor: { multiplicity: "[0..1]", type: "Max70Text" }
    postBox: { multiplicity: "[0..1]", type: "Max16Text" }
    room: { multiplicity: "[0..1]", type: "Max70Text" }
    postCode: { multiplicity: "[0..1]", type: "Max16Text" }
    townName: { multiplicity: "[1..1]", type: "Text" }
    townLocationName: { multiplicity: "[0..1]", type: "Text" }
    districtName: { multiplicity: "[0..1]", type: "Text" }
    countrySubDivision: { multiplicity: "[0..1]", type: "Text" }
    addressLine: { multiplicity: "[0..7]", type: "Max35Text", constraints: ["C8"] }
    country: { multiplicity: "[1..1]", type: "CountryCode", constraints: ["C3"] }
  constraints:
    C3: "country must be ISO-3166-1 alpha-2 or 'XX'"
    C8: "At least one of: addressLine OR (streetName AND (buildingName OR buildingNumber))"
  codeLists:
    AddressTypeCode: ["HOME", "BIZZ", "GEOG"]
    CountryCode: "ISO-3166-1 alpha-2, or 'XX' (regex: ^[A-Z]{2}$)"

NationalIdentification:
  structure:
    nationalIdentifier: { multiplicity: "[1..1]", type: "Max35Text", constraints: ["C11? for LEIX"] }
    nationalIdentifierType: { multiplicity: "[1..1]", type: "NationalIdentifierTypeCode", constraints: ["C7", "C9", "C11"] }
    countryOfIssue: { multiplicity: "[0..1]", type: "CountryCode", constraints: ["C3", "C9"] }
    registrationAuthority: { multiplicity: "[0..1]", type: "RegistrationAuthority", constraints: ["C9", "C10"] }
  constraints:
    C7: "For LegalPerson, nationalIdentifierType must be one of RAID|MISC|LEIX|TXID"
    C9: "For LegalPerson: if type != LEIX, MUST have countryOfIssue; if type == LEIX, MUST NOT have registrationAuthority"
    C10: "registrationAuthority must be on GLEIF Registration Authorities List (format RA\d{6})"
    C11: "If type == LEIX, nationalIdentifier must be LEIText (20-char regex ^[0-9A-Z]{18}[0-9]{2}$)"
  codeLists:
    NationalIdentifierTypeCode:
      legalPersonAllowed: ["RAID", "MISC", "LEIX", "TXID"]
      othersCommon: ["ARNU", "CCPT", "DRLC", "FIIN", "SOCS", "IDCD", "TXID"]
    RegistrationAuthority: "Text 'RA' followed by 6 digits (e.g., RA000553)"
    CountryCode: "ISO-3166-1 alpha-2, or 'XX'"

LegalPersonName:
  structure:
    nameIdentifier: 
      multiplicity: "[1..n]"
      item:
        legalPersonName: { type: "Text" }
        legalPersonNameIdentifierType: { type: "LegalPersonNameTypeCode" }
    localNameIdentifier:
      multiplicity: "[0..n]"
      item:
        legalPersonName: { type: "Text" }
        legalPersonNameIdentifierType: { type: "LegalPersonNameTypeCode" }
    phoneticNameIdentifier:
      multiplicity: "[0..n]"
      item:
        legalPersonName: { type: "Text" }
        legalPersonNameIdentifierType: { type: "LegalPersonNameTypeCode" }
  codeLists:
    LegalPersonNameTypeCode: ["LEGL", "SHRT", "TRAD"]
  constraints:
    C5: "At least one nameIdentifier must have legalPersonNameIdentifierType == 'LEGL'"

NaturalPersonName:
  structure:
    nameIdentifier:
      multiplicity: "[1..n]"
      item:
        primaryIdentifier: { type: "Text" }
        secondaryIdentifier: { type: "Text", multiplicity: "[0..1]" }
        naturalPersonNameIdentifierType: { type: "NaturalPersonNameTypeCode" }
    localNameIdentifier:
      multiplicity: "[0..n]"
      item:
        primaryIdentifier: { type: "LocalMax100Text" }
        secondaryIdentifier: { type: "LocalMax100Text", multiplicity: "[0..1]" }
        nameIdentifierType: { type: "NaturalPersonNameTypeCode" }
    phoneticNameIdentifier:
      multiplicity: "[0..n]"
      item:
        primaryIdentifier: { type: "LocalMax100Text" }
        secondaryIdentifier: { type: "LocalMax100Text", multiplicity: "[0..1]" }
        nameIdentifierType: { type: "NaturalPersonNameTypeCode" }
  codeLists:
    NaturalPersonNameTypeCode: ["LEGL", "ALIA", "BIRT", "MAID", "MISC"]

DateAndPlaceOfBirth:
  structure:
    dateOfBirth: { multiplicity: "[1..1]", type: "Date", constraints: ["C2"] }
    placeOfBirth: { multiplicity: "[1..1]", type: "Max70Text" }
  constraints:
    C2: "dateOfBirth must be a historic date (prior to today)"
  datatypes:
    Date: "YYYY-MM-DD (ISO 8601)"

LegalPerson:
  structure:
    name: { multiplicity: "[1..1]", type: "LegalPersonName", constraints: ["C5"] }
    geographicAddress: { multiplicity: "[0..n]", type: "Address", constraints: ["C3", "C4", "C8"] }
    customerIdentification: { multiplicity: "[0..1]", type: "Text", constraints: ["C4"] }
    nationalIdentification: { multiplicity: "[0..1]", type: "NationalIdentification", constraints: ["C3", "C4", "C7", "C9", "C10", "C11"] }
    countryOfRegistration: { multiplicity: "[0..1]", type: "CountryCode", constraints: ["C3"] }
  constraints:
    C4: "If originator is LegalPerson, at least one of (geographicAddress with GEOG) OR nationalIdentification OR customerIdentification is required"
    C5: "At least one LEGL name in nameIdentifier[]"

NaturalPerson:
  structure:
    name: { multiplicity: "[1..1]", type: "NaturalPersonName", constraints: ["C6"] }
    geographicAddress: { multiplicity: "[0..n]", type: "Address", constraints: ["C3", "C1", "C8"] }
    nationalIdentification: { multiplicity: "[0..1]", type: "NationalIdentification", constraints: ["C3"] }
    customerIdentification: { multiplicity: "[0..1]", type: "Text", constraints: ["C1"] }
    dateAndPlaceOfBirth: { multiplicity: "[0..1]", type: "DateAndPlaceOfBirth", constraints: ["C1", "C2"] }
    countryOfResidence: { multiplicity: "[0..1]", type: "CountryCode", constraints: ["C3"] }
  constraints:
    C1: "If originator is NaturalPerson, at least one of (geographicAddress with HOME/BIZZ/GEOG) OR customerIdentification OR nationalIdentification OR dateAndPlaceOfBirth is required"
    C2: "If present, dateOfBirth must be in the past"
    C6: "At least one LEGL name in nameIdentifier[]"

Person:
  description: "Holds either a NaturalPerson or a LegalPerson, plus optional accountNumber(s)."
  structure:
    naturalPerson: { multiplicity: "[0..1]", type: "NaturalPerson" }
    legalPerson: { multiplicity: "[0..1]", type: "LegalPerson" }
    accountNumber: { multiplicity: "[0..n]", type: "Max512Text" }

Originator:
  structure:
    originatorPerson: { multiplicity: "[1..n]", type: "Person", constraints: ["C1", "C2", "C3", "C4", "C5", "C6", "C7", "C8", "C9", "C10", "C11"] }

Beneficiary:
  structure:
    beneficiaryPerson: { multiplicity: "[1..n]", type: "Person" }

# Useful datatypes (selection)
datatypes:
  Max35Text: { regex: "^[ -~]{1,35}$" }
  Max16Text: { regex: "^[ -~]{1,16}$" }
  Max512Text: { regex: "^[ -~]{1,512}$" }
  LEIText: { regex: "^[0-9A-Z]{18}[0-9]{2}$", length: 20 }

{
  "ivms101": {
    "PayloadMetadata": {
      "payloadVersion": "IVMS101.2023"
    },
    "originator": {
      "originatorPerson": [
        {
          "legalPerson": {
            "name": {
              "nameIdentifier": [
                {
                  "legalPersonName": "{{$randomCompanyName}}",
                  "legalPersonNameIdentifierType": "LEGL"
                }
              ]
            },
            "geographicAddress": [
              {
                "addressType": "GEOG",
                "streetName": "{{$randomStreetAddress}}",
                "townName": "{{$randomCity}}",
                "country": "{{$randomCountryCode}}",
                "buildingNumber": "{{$randomInt}}",
                "postCode": "{{$randomInt}}-{{$randomInt}}"
              }
            ],
            "nationalIdentification": {
              "nationalIdentifier": "{{$randomPassword}}",
              "nationalIdentifierType": "TXID",
              // "registrationAuthority": "RA000000", only include this if ID type is LEIX: https://www.gleif.org/en/lei-data/code-lists/gleif-registration-authorities-list
              "countryOfIssue": "{{$randomCountryCode}}"  // include this if ID type is not LEIX
            },
            "customerIdentification": "{{$randomUUID}}",
            "countryOfRegistration": "{{$randomCountryCode}}"
          },
        "accountNumber": ["{{$randomBankAccount}}"]
        }
      ]
    },
    "beneficiary": {
      "beneficiaryPerson": [
        {
          "legalPerson": {
            "name": {
              "nameIdentifier": [
                {
                  "legalPersonName": "{{$randomCompanyName}}",
                  "legalPersonNameIdentifierType": "LEGL"
                }
              ]
            }
          },
          "accountNumber": ["{{$randomBankAccount}}"]
        }
      ]
    }
  }
}

{
    "settlementId": "{{$randomUUID}}" // once the transaction has been broadcast, append the transaction hash to the message you sent
    // "settlementIdIndex": "1" // if required
}

{
    "reason": "BENEFICIARY_ADDRESS",
